import React, { useEffect, useState } from "react";
import { getBuses } from "../api/api";
import BookingForm from "./BookingForm";

const BusList = () => {
  const [buses, setBuses] = useState([]);
  const [selectedBus, setSelectedBus] = useState(null);

  useEffect(() => {
    getBuses().then(res => setBuses(res.data));
  }, []);

  return (
    <div>
      <h3>Available Buses</h3>
      <ul>
        {buses.map(bus => (
          <li key={bus.id}>
            {bus.name} - {bus.source} to {bus.destination} at {bus.time} - Seats: {bus.seats_available}
            <button onClick={() => setSelectedBus(bus)}>Book</button>
          </li>
        ))}
      </ul>

      {selectedBus && <BookingForm bus={selectedBus} onClose={() => setSelectedBus(null)} />}
    </div>
  );
};

export default BusList;
